import React, { useState, useCallback, useRef, useEffect, Suspense } from 'react'
import { GameHeader } from '../ui/GameHeader'
import { GameOverlay } from '../ui/GameOverlay'
import { isMobile } from '../../../../utils/functions'
import { CandyCrushProps } from './types'
import { LEVELS, SCORING } from './constants'
import { candyCrushAudio } from './utils/audioManager'

const CandyCrushCore = React.lazy(() => import('./game'))

const CandyCrushGame: React.FC<CandyCrushProps> = ({
	lives = 3,
	level = 1,
	setGameOver,
	setPointsEarned,
	brandColor = '#e91e63',
	skin,
	gameTitle = 'CANDY CRUSH',
	brandLogo,
	maxPoints,
}) => {
	const containerRef = useRef<HTMLDivElement>(null)
	const [gameKey, setGameKey] = useState(0) // Used to reset game instance

	// Level progression state
	const [currentLevel, setCurrentLevel] = useState(
		Math.min(Math.max(level, 1), LEVELS.length)
	)
	const [totalScore, setTotalScore] = useState(0) // Accumulated score across all levels

	// Get level configuration for current level
	const levelConfig = LEVELS[currentLevel - 1]

	// Game state
	const [score, setScore] = useState(0) // Score for current level
	const [moves, setMoves] = useState(levelConfig.moves)
	const [livesRemaining, setLivesRemaining] = useState(lives)
	const [isGameStarted, setIsGameStarted] = useState(false)
	const [isRoundComplete, setIsRoundComplete] = useState(false)
	const [roundWon, setRoundWon] = useState(false)
	const [isGameOver, setIsGameOver] = useState(false)
	const [quitGame, setQuitGame] = useState(false)
	const [allLevelsComplete, setAllLevelsComplete] = useState(false)

	// Refs to access current values in callbacks without causing re-renders
	const scoreRef = useRef(score)
	const totalScoreRef = useRef(totalScore)
	const currentLevelRef = useRef(currentLevel)
	const livesRemainingRef = useRef(livesRemaining)

	// Cleanup audio on unmount
	useEffect(() => {
		return () => {
			candyCrushAudio.dispose()
		}
	}, [])

	// Keep refs in sync with state
	useEffect(() => {
		scoreRef.current = score
	}, [score])
	useEffect(() => {
		totalScoreRef.current = totalScore
	}, [totalScore])
	useEffect(() => {
		currentLevelRef.current = currentLevel
	}, [currentLevel])
	useEffect(() => {
		livesRemainingRef.current = livesRemaining
	}, [livesRemaining])

	const isMobileDevice = isMobile()

	const startGame = useCallback(async () => {
		if (!isGameStarted) {
			// Initialize audio on user gesture (required for browser audio context)
			await candyCrushAudio.init()

			setIsGameStarted(true)
			setIsRoundComplete(false)
			setRoundWon(false)
			setIsGameOver(false)
			setScore(0)
			setMoves(levelConfig.moves)
			setQuitGame(false)
			setGameKey(prev => prev + 1)
		}
	}, [isGameStarted, levelConfig.moves])

	const retryRound = useCallback(() => {
		setIsRoundComplete(false)
		setRoundWon(false)
		setScore(0)
		setMoves(levelConfig.moves)
		setGameKey(prev => prev + 1)
	}, [levelConfig.moves])

	const cancelQuit = () => {
		setQuitGame(false)
	}

	const handleQuitConfirm = useCallback(() => {
		// Use refs to ensure we get the latest values
		const finalScore = totalScoreRef.current + scoreRef.current
		setPointsEarned(finalScore)
		setGameOver(true)
		setIsGameStarted(false)
		setIsGameOver(true)
	}, [setPointsEarned, setGameOver])

	const handleScoreUpdate = useCallback(
		(newScore: number) => {
			setScore(newScore)
			const effectiveScore = totalScoreRef.current + newScore
			if (maxPoints && effectiveScore >= maxPoints) {
				setIsGameOver(true)
				setIsRoundComplete(true)
				setRoundWon(true)
				setAllLevelsComplete(true)
				setPointsEarned(Math.min(effectiveScore, maxPoints))
				setGameOver(true)
			}
		},
		[maxPoints, setPointsEarned, setGameOver]
	)

	const handleMovesUpdate = useCallback((newMoves: number) => {
		setMoves(newMoves)
	}, [])

	const handleGameComplete = useCallback(
		(won: boolean, _finalScore: number) => {
			setRoundWon(won)
			setIsRoundComplete(true)

			if (won) {
				// Check if this was the last level
				if (currentLevelRef.current >= LEVELS.length) {
					// Completed all levels! Add final score to total
					setTotalScore(prev => prev + scoreRef.current)
					setAllLevelsComplete(true)
					setIsGameOver(true)
				}
				// Otherwise, player can continue to next level (score added when they click Next)
			} else {
				// Player failed - lose a life
				const newLives = livesRemainingRef.current - 1
				setLivesRemaining(newLives)

				if (newLives <= 0) {
					// No more lives - game over
					setIsGameOver(true)
				}
				// Otherwise, player can retry
			}
		},
		[]
	)

	const handleNextLevel = useCallback(() => {
		// Add current level score to total before advancing
		setTotalScore(prev => prev + score)

		// Advance to next level
		const nextLevel = currentLevel + 1
		const nextLevelConfig = LEVELS[nextLevel - 1]

		setCurrentLevel(nextLevel)
		setIsRoundComplete(false)
		setRoundWon(false)
		setScore(0)
		setMoves(nextLevelConfig.moves)
		setGameKey(prev => prev + 1)
	}, [currentLevel, score])

	const handleContinue = () => {
		setPointsEarned(totalScore + score)
		setGameOver(true)
	}

	return (
		<div
			className="game-container game-column-narrow"
			style={{ backgroundColor: brandColor }}
			ref={containerRef}
		>
			{/* Game Header - Score, Moves, Lives, Level */}
			<GameHeader
				level={currentLevel}
				score={totalScore + score}
				lives={livesRemaining}
				brandColor={brandColor}
				isMobile={isMobileDevice}
				onQuit={() => setQuitGame(true)}
				showQuitButton={isGameStarted && !isRoundComplete && !isGameOver}
				isQuitting={quitGame}
			/>

			{/* Game Canvas Area */}
			<div className="game-center-area">
				<div
					className="game-relative-area"
					style={{ aspectRatio: '400/600', maxHeight: '70vh' }}
				>
					{/* Start Screen */}
					{!isGameStarted && !isGameOver && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={startGame}
							actionText="🍬 JUGAR"
							showPressToStart={false}
							customContent={
								<div className="game-start-content">
									<h1 className="game-start-title game-animate-pulse" style={{ color: '#f472b6' }}>
										{gameTitle}
									</h1>
									{brandLogo && (
										<>
											<span className="game-brand-label">por:</span>
											<img
												src={brandLogo}
												alt="Brand Logo"
												className="game-brand-logo"
											/>
										</>
									)}
									<p style={{ fontSize: '1.125rem', fontWeight: 'bold', color: 'white' }}>
										Nivel {currentLevel} de {LEVELS.length}
									</p>
									<div className="game-start-instructions">
										<p>🎯 Meta: {levelConfig.targetScore} puntos</p>
										<p>🔄 Movimientos: {levelConfig.moves}</p>
										<p>❤️ Vidas: {lives}</p>
										<p>👆 Desliza para intercambiar dulces</p>
									</div>
									<div className="game-start-footer">
										<p>Combina 3+ dulces del mismo color</p>
									</div>
								</div>
							}
						/>
					)}

					{/* Active Game */}
					{isGameStarted && !isRoundComplete && (
						<Suspense fallback={<div className="game-loading-fallback"><div className="game-loading-text game-animate-pulse">Cargando...</div></div>}>
						<CandyCrushCore
							key={gameKey}
							onScoreUpdate={handleScoreUpdate}
							onMovesUpdate={handleMovesUpdate}
							onGameComplete={handleGameComplete}
							brandColor={brandColor}
							skin={skin}
							lives={livesRemaining}
							levelConfig={levelConfig}
						/>
						</Suspense>
					)}

					{/* Round Complete - Success (not last level) */}
					{isRoundComplete && roundWon && !allLevelsComplete && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={handleNextLevel}
							actionText="Siguiente Nivel ➡️"
							customContent={
								<div className="game-start-content-lg">
									<h1 className="game-start-title-lg" style={{ color: '#4ade80' }}>
										¡Nivel {currentLevel} Completado!
									</h1>
									<div className="game-emoji-xl game-animate-bounce">🎉</div>
									<p style={{ fontSize: '1.25rem', color: 'white' }}>Alcanzaste la meta</p>

									{/* Score breakdown */}
									<div className="game-score-breakdown">
										<div className="game-score-row">
											<span>Puntuación base:</span>
											<span>{score - moves * SCORING.movesBonus}</span>
										</div>
										{moves > 0 && (
											<div className="game-score-row" style={{ color: '#4ade80' }}>
												<span>Bonus por turnos:</span>
												<span>
													{moves} × {SCORING.movesBonus} = +
													{moves * SCORING.movesBonus}
												</span>
											</div>
										)}
										<div className="game-score-row game-score-row-highlight game-score-divider" style={{ color: '#facc15' }}>
											<span>Total nivel:</span>
											<span>{score}</span>
										</div>
									</div>

									<p style={{ fontSize: '1rem', color: '#d1d5db' }}>
										Puntuación acumulada:{' '}
										<span style={{ color: '#facc15', fontWeight: 'bold' }}>
											{totalScore + score}
										</span>
									</p>
								</div>
							}
						/>
					)}

					{/* All Levels Complete */}
					{isRoundComplete && roundWon && allLevelsComplete && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={handleContinue}
							actionText="🏆 Finalizar"
							customContent={
								<div className="game-start-content-lg">
									<h1 className="game-start-title-lg" style={{ color: '#facc15' }}>
										¡VICTORIA TOTAL!
									</h1>
									<div className="game-emoji-xl game-animate-bounce">🏆</div>
									<p style={{ fontSize: '1.25rem', color: 'white' }}>
										¡Completaste los {LEVELS.length} niveles!
									</p>

									{/* Final level score breakdown */}
									<div className="game-score-breakdown">
										<div className="game-score-row">
											<span>Puntuación base (nivel {currentLevel}):</span>
											<span>{score - moves * SCORING.movesBonus}</span>
										</div>
										{moves > 0 && (
											<div className="game-score-row" style={{ color: '#4ade80' }}>
												<span>Bonus por turnos:</span>
												<span>
													{moves} × {SCORING.movesBonus} = +
													{moves * SCORING.movesBonus}
												</span>
											</div>
										)}
										<div className="game-score-row game-score-divider">
											<span>Total nivel {currentLevel}:</span>
											<span>{score}</span>
										</div>
										<div className="game-score-row">
											<span>Niveles anteriores:</span>
											<span>{totalScore}</span>
										</div>
										<div className="game-score-row game-score-row-highlight game-score-divider" style={{ color: '#facc15', fontSize: '1.125rem' }}>
											<span>Puntuación final:</span>
											<span>{totalScore + score}</span>
										</div>
									</div>

									<p style={{ fontSize: '0.875rem', color: '#9ca3af' }}>
										Vidas restantes: {livesRemaining}
									</p>
								</div>
							}
						/>
					)}

					{/* Round Complete - Failed but has lives */}
					{isRoundComplete && !roundWon && !isGameOver && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={retryRound}
							actionText="🔄 Reintentar"
							customContent={
								<div className="game-start-content-lg">
									<h1 className="game-start-title-lg" style={{ color: '#fb923c' }}>
										¡Casi!
									</h1>
									<div className="game-emoji-xl">😢</div>
									<p style={{ fontSize: '1.25rem', color: 'white' }}>
										{score} / {levelConfig.targetScore} puntos
									</p>
									<div className="game-lives-display">
										{Array.from({ length: lives }).map((_, i) => (
											<span
												key={i}
												style={{ fontSize: '1.5rem', opacity: i < livesRemaining ? 1 : 0.3 }}
											>
												❤️
											</span>
										))}
									</div>
									<p style={{ fontSize: '0.875rem', color: '#d1d5db' }}>
										Vidas restantes: {livesRemaining}
									</p>
								</div>
							}
						/>
					)}

					{/* Game Over - No more lives */}
					{isGameOver && !roundWon && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={handleContinue}
							actionText="Continuar"
							customContent={
								<div className="game-start-content-lg">
									<h1 className="game-start-title-lg" style={{ color: '#f87171' }}>
										GAME OVER
									</h1>
									<div className="game-emoji-xl">💔</div>
									<p style={{ fontSize: '1.25rem', color: 'white' }}>Se acabaron las vidas</p>
									<p style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#facc15' }}>
										{score} puntos
									</p>
								</div>
							}
						/>
					)}

					{/* Quit Confirmation */}
					{quitGame && (
						<GameOverlay
							type="custom"
							title="¿Salir del Juego?"
							message={`¿Seguro? Registrarás tus puntos actuales (${totalScore + score}) y terminarás la partida.`}
							brandColor={brandColor}
							customContent={
								<div className="game-quit-buttons">
									<button
										onClick={cancelQuit}
										className="game-quit-btn game-quit-btn-cancel"
									>
										🔄 Cancelar
									</button>
									<button
										onClick={handleQuitConfirm}
										className="game-quit-btn game-quit-btn-confirm"
									>
										❌ Salir
									</button>
								</div>
							}
						/>
					)}
				</div>
			</div>

			{/* Ad Space */}
			<div className="game-full-width">
				<img
					src={`/games/candy-crush/sprites/${skin ? `skins/${skin}/` : ''}ad-bottom.webp`}
					alt="Advertisement"
					className="game-ad-image"
				/>
			</div>
		</div>
	)
}

export default CandyCrushGame
