// Actor base class for Pac-Man game entities

import { TILE_SIZE, MID_TILE, SPEED_TABLE } from '../constants'
import { Direction, Position, TilePosition, SpeedPattern } from '../types'
import { setDirFromEnum } from './Direction'
import type { GameMap } from './Map'

/**
 * Base Actor class for movement and positioning
 * Ghost and Player classes inherit from this
 */
export class Actor {
	// Position data
	pixel: Position = { x: 0, y: 0 }
	tile: TilePosition = { x: 0, y: 0 }
	tilePixel: Position = { x: 0, y: 0 }
	distToMid: Position = { x: 0, y: 0 }

	// Direction data
	dir: Position = { x: 0, y: 0 }
	dirEnum: Direction = Direction.LEFT

	// Targeting
	targetTile: TilePosition = { x: 0, y: 0 }
	targetting: string | undefined = undefined

	// Frame counters
	frames: number = 0
	steps: number = 0

	// Starting position
	startPixel: Position = { x: 0, y: 0 }
	startDirEnum: Direction = Direction.LEFT

	// Reference to game map
	protected map: GameMap | null = null


	/**
	 * Set the map reference for this actor
	 */
	setMap(map: GameMap): void {
		this.map = map
	}

	/**
	 * Reset to initial position and direction
	 */
	reset(): void {
		this.setDir(this.startDirEnum)
		this.setPos(this.startPixel.x, this.startPixel.y)
		this.frames = 0
		this.steps = 0
		this.targetting = undefined
	}

	/**
	 * Set position and update dependent variables
	 */
	setPos(px: number, py: number): void {
		this.pixel.x = px
		this.pixel.y = py
		this.commitPos()
	}

	/**
	 * Get relative pixel position inside a tile
	 */
	getTilePixel(pixel?: Position, tilePixel?: Position): Position {
		const p = pixel || this.pixel
		const tp = tilePixel || { x: 0, y: 0 }

		tp.x = p.x % TILE_SIZE
		tp.y = p.y % TILE_SIZE

		if (tp.x < 0) tp.x += TILE_SIZE
		if (tp.y < 0) tp.y += TILE_SIZE

		return tp
	}

	/**
	 * Update position-dependent variables
	 */
	commitPos(): void {
		// Use map teleport if available
		if (this.map) {
			this.map.teleport(this)
		}

		this.tile.x = Math.floor(this.pixel.x / TILE_SIZE)
		this.tile.y = Math.floor(this.pixel.y / TILE_SIZE)
		this.getTilePixel(this.pixel, this.tilePixel)
		this.distToMid.x = MID_TILE.x - this.tilePixel.x
		this.distToMid.y = MID_TILE.y - this.tilePixel.y
	}

	/**
	 * Set direction from enum
	 */
	setDir(dirEnum: Direction): void {
		setDirFromEnum(this.dir, dirEnum)
		this.dirEnum = dirEnum
	}

	/**
	 * Get step size from speed table based on level and pattern
	 */
	getStepSizeFromTable(level: number, pattern: SpeedPattern): number {
		if (level < 1) return 0

		let entry: number
		if (level === 1) entry = 0
		else if (level >= 2 && level <= 4) entry = 1
		else if (level >= 5 && level <= 20) entry = 2
		else entry = 3

		const index = entry * 7 * 16 + pattern * 16 + (this.frames % 16)
		return parseInt(SPEED_TABLE[index], 10)
	}

	/**
	 * Get number of steps to take this frame
	 * Override in subclasses
	 */
	getNumSteps(): number {
		return 1
	}

	/**
	 * Move forward one pixel
	 * Override in subclasses
	 */
	step(): number {
		this.setPos(this.pixel.x + this.dir.x, this.pixel.y + this.dir.y)
		return 1
	}

	/**
	 * Update direction/steering
	 * Override in subclasses
	 */
	steer(): void {
		// Base implementation does nothing
	}

	/**
	 * Update actor state for this substep
	 */
	update(substep: number): void {
		const numSteps = this.getNumSteps()
		if (substep >= numSteps) return

		// Move one step and increment counter if step taken
		this.steps += this.step()

		// Update direction
		this.steer()
	}
}
