// Canvas renderer for Pac-Man game

import { TILE_SIZE, MID_TILE, SCALE, MAP_COLORS } from '../constants'
import { Direction, GhostMode } from '../types'
import type { GameMap } from '../core/Map'
import type { Player } from '../core/Player'
import type { Ghost } from '../core/Ghost'
import type { Energizer } from '../systems/Energizer'
import {
	drawGhostSprite,
	drawPacmanSprite,
	getPacmanAngle,
	drawFruitSprite,
	drawFruitScore,
} from './sprites'
import type { Fruit } from '../core/Fruit'

/**
 * Pac-Man game renderer
 */
export class Renderer {
	private ctx: CanvasRenderingContext2D
	private mapCanvas: HTMLCanvasElement | null = null
	private mapCtx: CanvasRenderingContext2D | null = null
	private pelletCanvas: HTMLCanvasElement | null = null
	private pelletCtx: CanvasRenderingContext2D | null = null

	constructor(ctx: CanvasRenderingContext2D) {
		this.ctx = ctx
	}

	/**
	 * Initialize off-screen canvases for map and pellets
	 */
	initMapCanvas(map: GameMap): void {
		// Create map canvas for walls
		this.mapCanvas = document.createElement('canvas')
		this.mapCanvas.width = map.widthPixels * SCALE
		this.mapCanvas.height = map.heightPixels * SCALE
		this.mapCtx = this.mapCanvas.getContext('2d')

		// Create pellet canvas
		this.pelletCanvas = document.createElement('canvas')
		this.pelletCanvas.width = map.widthPixels * SCALE
		this.pelletCanvas.height = map.heightPixels * SCALE
		this.pelletCtx = this.pelletCanvas.getContext('2d')

		// Render static map
		this.renderMapWalls(map)
		this.renderPellets(map)
	}

	/**
	 * Render maze walls to off-screen canvas
	 */
	private renderMapWalls(map: GameMap): void {
		if (!this.mapCtx) return

		const ctx = this.mapCtx
		ctx.save()
		ctx.scale(SCALE, SCALE)

		// Fill background
		ctx.fillStyle = map.wallFillColor || MAP_COLORS.wallFill
		ctx.fillRect(0, 0, map.widthPixels, map.heightPixels)

		// Draw wall paths
		ctx.strokeStyle = map.wallStrokeColor || MAP_COLORS.wallStroke
		ctx.lineWidth = 2
		ctx.lineCap = 'round'
		ctx.lineJoin = 'round'

		for (const path of map.paths) {
			ctx.beginPath()
			for (let i = 0; i < path.length; i++) {
				const point = path[i]
				if (i === 0) {
					ctx.moveTo(point.x, point.y)
				} else if (point.cx !== undefined && point.cy !== undefined) {
					ctx.quadraticCurveTo(point.cx, point.cy, point.x, point.y)
				} else {
					ctx.lineTo(point.x, point.y)
				}
			}
			ctx.closePath()
			ctx.stroke()
		}

		ctx.restore()
	}

	/**
	 * Render pellets to off-screen canvas
	 */
	renderPellets(map: GameMap): void {
		if (!this.pelletCtx) return

		const ctx = this.pelletCtx
		ctx.clearRect(0, 0, map.widthPixels * SCALE, map.heightPixels * SCALE)
		ctx.save()
		ctx.scale(SCALE, SCALE)

		const pelletColor = map.pelletColor || MAP_COLORS.pellet

		// Draw pellets
		for (let y = 0; y < map.numRows; y++) {
			for (let x = 0; x < map.numCols; x++) {
				const tile = map.getTile(x, y)
				const px = x * TILE_SIZE + MID_TILE.x
				const py = y * TILE_SIZE + MID_TILE.y

				if (tile === '.') {
					// Small pellet
					ctx.fillStyle = pelletColor
					ctx.beginPath()
					ctx.arc(px, py, 1, 0, Math.PI * 2)
					ctx.fill()
				} else if (tile === 'o') {
					// Energizer (large pellet)
					ctx.fillStyle = pelletColor
					ctx.beginPath()
					ctx.arc(px, py, 4, 0, Math.PI * 2)
					ctx.fill()
				}
			}
		}

		ctx.restore()
	}

	/**
	 * Clear the main canvas
	 */
	clear(): void {
		this.ctx.fillStyle = '#000'
		this.ctx.fillRect(0, 0, this.ctx.canvas.width, this.ctx.canvas.height)
	}

	/**
	 * Draw the complete frame
	 */
	render(
		map: GameMap,
		player: Player,
		ghosts: Ghost[],
		energizer: Energizer,
		frame: number,
		fruit?: Fruit | null
	): void {
		this.clear()

		// Draw walls from off-screen canvas
		if (this.mapCanvas) {
			this.ctx.drawImage(this.mapCanvas, 0, 0)
		}

		// Draw pellets (with energizer blink)
		this.drawPellets(map, frame)

		// Draw fruit
		if (fruit) {
			this.drawFruit(fruit)
		}

		// Draw ghosts
		for (const ghost of ghosts) {
			this.drawGhost(ghost, energizer)
		}

		// Draw Pac-Man
		this.drawPlayer(player)

		// Draw points if showing
		if (energizer.showingPoints()) {
			// Points would be drawn at last eaten ghost position
			// For now we skip this as it requires tracking eaten ghost position
		}
	}

	/**
	 * Draw fruit or fruit score
	 */
	private drawFruit(fruit: Fruit): void {
		const ctx = this.ctx
		ctx.save()
		ctx.scale(SCALE, SCALE)

		if (fruit.isPresent()) {
			drawFruitSprite(
				ctx,
				fruit.pixel.x,
				fruit.pixel.y,
				fruit.getCurrentFruit().name
			)
		} else if (fruit.isShowingScore()) {
			drawFruitScore(
				ctx,
				fruit.pixel.x,
				fruit.pixel.y,
				fruit.getCurrentFruit().points
			)
		}

		ctx.restore()
	}

	/**
	 * Draw pellets
	 */
	private drawPellets(map: GameMap, _frame: number): void {
		if (!this.pelletCtx) return

		const ctx = this.ctx
		ctx.save()
		ctx.scale(SCALE, SCALE)

		const pelletColor = map.pelletColor || MAP_COLORS.pellet

		// Draw pellets
		for (let y = 0; y < map.numRows; y++) {
			for (let x = 0; x < map.numCols; x++) {
				const tile = map.getTile(x, y)
				const px = x * TILE_SIZE + MID_TILE.x
				const py = y * TILE_SIZE + MID_TILE.y

				if (tile === '.') {
					// Small pellet
					ctx.fillStyle = pelletColor
					ctx.beginPath()
					ctx.arc(px, py, 1, 0, Math.PI * 2)
					ctx.fill()
				} else if (tile === 'o') {
					// Energizer (large pellet)
					ctx.fillStyle = pelletColor
					ctx.beginPath()
					ctx.arc(px, py, 4, 0, Math.PI * 2)
					ctx.fill()
				}
			}
		}

		ctx.restore()
	}

	/**
	 * Draw Pac-Man
	 */
	private drawPlayer(player: Player): void {
		const ctx = this.ctx
		ctx.save()
		ctx.scale(SCALE, SCALE)

		const animFrame = player.getAnimFrame()
		const angle = getPacmanAngle(animFrame)

		drawPacmanSprite(ctx, player.pixel.x, player.pixel.y, player.dirEnum, angle)

		ctx.restore()
	}

	/**
	 * Draw a ghost
	 */
	private drawGhost(ghost: Ghost, energizer: Energizer): void {
		const ctx = this.ctx
		ctx.save()
		ctx.scale(SCALE, SCALE)

		const animFrame = ghost.getAnimFrame()
		const scared = ghost.scared
		const flash = scared && energizer.isFlash()
		const eyesOnly =
			ghost.mode === GhostMode.GOING_HOME ||
			ghost.mode === GhostMode.ENTERING_HOME

		drawGhostSprite(
			ctx,
			ghost.pixel.x,
			ghost.pixel.y,
			animFrame,
			ghost.faceDirEnum,
			scared,
			flash,
			eyesOnly,
			ghost.color
		)

		ctx.restore()
	}

	/**
	 * Draw Pac-Man death animation
	 */
	drawDeathAnimation(player: Player, deathFrame: number): void {
		const ctx = this.ctx
		ctx.save()
		ctx.scale(SCALE, SCALE)

		// Death animation: Pac-Man shrinks/expands mouth then disappears
		const totalFrames = 60
		const progress = deathFrame / totalFrames

		if (progress < 1) {
			// Mouth opens wider and wider, then body shrinks
			let angle = Math.PI * Math.min(progress * 1.5, 1)

			drawPacmanSprite(ctx, player.pixel.x, player.pixel.y, Direction.UP, angle)
		}

		ctx.restore()
	}

	/**
	 * Draw score and lives
	 */
	drawHUD(score: number, lives: number, level: number): void {
		const ctx = this.ctx

		// Score (top left)
		ctx.fillStyle = '#FFF'
		ctx.font = `${12 * SCALE}px monospace`
		ctx.textAlign = 'left'
		ctx.fillText(`SCORE: ${score}`, 8 * SCALE, 16 * SCALE)

		// Level (top right)
		ctx.textAlign = 'right'
		ctx.fillText(`LEVEL ${level}`, (28 * TILE_SIZE - 8) * SCALE, 16 * SCALE)

		// Lives (bottom left) - draw small Pac-Man sprites
		ctx.save()
		for (let i = 0; i < lives - 1; i++) {
			ctx.save()
			ctx.scale(SCALE, SCALE)
			drawPacmanSprite(
				ctx,
				16 + i * 16,
				35 * TILE_SIZE,
				Direction.LEFT,
				Math.atan(4 / 5)
			)
			ctx.restore()
		}
		ctx.restore()
	}

	/**
	 * Draw "READY!" text
	 */
	drawReady(): void {
		const ctx = this.ctx
		ctx.fillStyle = '#FF0'
		ctx.font = `bold ${14 * SCALE}px monospace`
		ctx.textAlign = 'center'
		ctx.fillText('READY!', 14 * TILE_SIZE * SCALE, (20 * TILE_SIZE + 4) * SCALE)
	}

	/**
	 * Draw "GAME OVER" text
	 */
	drawGameOver(): void {
		const ctx = this.ctx
		ctx.fillStyle = '#F00'
		ctx.font = `bold ${14 * SCALE}px monospace`
		ctx.textAlign = 'center'
		ctx.fillText(
			'GAME OVER',
			14 * TILE_SIZE * SCALE,
			(20 * TILE_SIZE + 4) * SCALE
		)
	}
}
