import { MathUtils } from '../utils/math'

/**
 * Optimized game loop with fixed timestep and frame rate management
 */
export class GameLoop {
	private isRunning = false
	private animationFrameId: number | null = null
	private lastTimestamp = 0
	private accumulator = 0
	private readonly targetFps: number
	private readonly fixedTimeStep: number
	private readonly maxFrameTime: number

	// Performance monitoring
	private frameCount = 0
	private lastFpsUpdate = 0
	private currentFps = 0

	constructor(
		private update: (dt: number) => void,
		private render: (interpolation: number) => void,
		fps: number = 60
	) {
		this.targetFps = fps
		this.fixedTimeStep = 1 / fps
		this.maxFrameTime = this.fixedTimeStep * 5 // Prevent spiral of death
	}

	/**
	 * Start the game loop
	 */
	start(): void {
		if (this.isRunning) return

		this.isRunning = true
		this.lastTimestamp = MathUtils.timestamp()
		this.accumulator = 0
		this.loop()
	}

	/**
	 * Stop the game loop
	 */
	stop(): void {
		this.isRunning = false
		if (this.animationFrameId !== null) {
			cancelAnimationFrame(this.animationFrameId)
			this.animationFrameId = null
		}
	}

	/**
	 * Get current FPS
	 */
	getFps(): number {
		return this.currentFps
	}

	/**
	 * Main game loop with fixed timestep
	 */
	private loop = (): void => {
		if (!this.isRunning) return

		const currentTime = MathUtils.timestamp()
		let frameTime = (currentTime - this.lastTimestamp) / 1000

		// Prevent spiral of death by capping frame time
		frameTime = Math.min(frameTime, this.maxFrameTime)
		this.lastTimestamp = currentTime
		this.accumulator += frameTime

		// Fixed timestep updates
		while (this.accumulator >= this.fixedTimeStep) {
			this.update(this.fixedTimeStep)
			this.accumulator -= this.fixedTimeStep
		}

		// Calculate interpolation for smooth rendering
		const interpolation = this.accumulator / this.fixedTimeStep

		// Render with interpolation
		this.render(interpolation)

		// Update FPS counter
		this.updateFpsCounter()

		// Schedule next frame
		this.animationFrameId = requestAnimationFrame(this.loop)
	}

	/**
	 * Update FPS counter
	 */
	private updateFpsCounter(): void {
		this.frameCount++
		const now = MathUtils.timestamp()

		if (now - this.lastFpsUpdate >= 1000) {
			this.currentFps = Math.round(
				(this.frameCount * 1000) / (now - this.lastFpsUpdate)
			)
			this.frameCount = 0
			this.lastFpsUpdate = now
		}
	}
}

/**
 * Image loader utility for game assets
 */
export class ImageLoader {
	/**
	 * Load multiple images and return them when all are loaded
	 */
	static async loadImages(
		names: string[],
		basePath: string,
		skin: string = 'default'
	): Promise<HTMLImageElement[]> {
		const promises = names.map(name =>
			this.loadSingleImage(name, basePath, skin)
		)
		return Promise.all(promises)
	}

	/**
	 * Load a single image
	 */
	private static loadSingleImage(
		name: string,
		basePath: string,
		skin: string
	): Promise<HTMLImageElement> {
		return new Promise((resolve, reject) => {
			const img = new Image()
			img.onload = () => resolve(img)
			img.onerror = () => reject(new Error(`Failed to load image: ${name}`))

			if (skin === 'default') {
				img.src = `${basePath}/${name}.webp`
			} else {
				img.src = `${basePath}/skins/${skin}/${name}.webp`
			}
		})
	}
}

/**
 * Input manager for keyboard and touch events
 */
export class InputManager {
	private keys: { [key: number]: boolean } = {}
	private keyHandlers: Array<{
		keys: number[]
		mode: 'up' | 'down'
		action: () => void
	}> = []

	constructor() {
		this.setupKeyboardListeners()
	}

	/**
	 * Setup keyboard event listeners
	 */
	private setupKeyboardListeners(): void {
		document.addEventListener('keydown', this.handleKeyDown)
		document.addEventListener('keyup', this.handleKeyUp)
	}

	/**
	 * Cleanup event listeners
	 */
	destroy(): void {
		document.removeEventListener('keydown', this.handleKeyDown)
		document.removeEventListener('keyup', this.handleKeyUp)
	}

	/**
	 * Register key handlers
	 */
	setKeyHandlers(
		handlers: Array<{
			keys: number[]
			mode: 'up' | 'down'
			action: () => void
		}>
	): void {
		this.keyHandlers = handlers
	}

	/**
	 * Check if key is pressed
	 */
	isKeyPressed(keyCode: number): boolean {
		return this.keys[keyCode] || false
	}

	/**
	 * Handle key down events
	 */
	private handleKeyDown = (event: KeyboardEvent): void => {
		this.keys[event.keyCode] = true
		this.triggerKeyHandlers(event.keyCode, 'down')

		// Prevent default for game keys
		const gameKeys = [37, 38, 39, 40] // Arrow keys
		if (gameKeys.includes(event.keyCode)) {
			event.preventDefault()
		}
	}

	/**
	 * Handle key up events
	 */
	private handleKeyUp = (event: KeyboardEvent): void => {
		this.keys[event.keyCode] = false
		this.triggerKeyHandlers(event.keyCode, 'up')
	}

	/**
	 * Trigger registered key handlers
	 */
	private triggerKeyHandlers(keyCode: number, mode: 'up' | 'down'): void {
		for (const handler of this.keyHandlers) {
			if (handler.mode === mode && handler.keys.includes(keyCode)) {
				handler.action()
			}
		}
	}

	/**
	 * Setup touch controls for mobile
	 */
	setupTouchControls(_isMobile: boolean): void {
		// Touch controls are now handled directly through the game component
		// This method is kept for compatibility but doesn't need to do anything
	}

	/**
	 * Get key code for touch direction
	 */
	private getKeyCodeForDirection(direction: string): number {
		switch (direction) {
			case 'left':
				return 37
			case 'up':
				return 38
			case 'right':
				return 39
			case 'down':
				return 40
			default:
				return 0
		}
	}
}
