import React, { useRef, useEffect, useState, useCallback, Suspense } from 'react'
import { GameHeader } from '../ui/GameHeader'
import { GameOverlay } from '../ui/GameOverlay'
import { GameControls } from '../ui/GameControls'
import { isMobile } from '../../../../utils/functions'
import { useImageLoader } from './hooks/useImageLoader'
import { DEFAULT_BOARD_SIZE, DEFAULT_CELL_SIZE, HUD_HEIGHT } from './constants'

interface SnakeGameProps {
	initialLives: number
	setGameOver: (isOver: boolean) => void
	setPointsEarned: (points: number) => void
	brandColor?: string
	skin?: string
	gameTitle?: string
	maxPoints?: number
	brandLogo?: string
}

const SnakeGameCore = React.lazy(() => import('./game'))

const SnakeGame: React.FC<SnakeGameProps> = ({
	initialLives,
	setGameOver,
	setPointsEarned,
	brandColor = '#10b981',
	skin,
	gameTitle = 'SNAKE',
	maxPoints,
	brandLogo,
}) => {
	const containerRef = useRef<HTMLDivElement>(null)
	const [images, imagesLoading, imagesError] = useImageLoader(skin)

	const [score, setScore] = useState(0)
	const [lives, setLives] = useState(initialLives)
	const [isPaused, setIsPaused] = useState(false)
	const [isGameStarted, setIsGameStarted] = useState(false)
	const [isGameOver, setIsGameOver] = useState(false)
	const [quitGame, setQuitGame] = useState(false)
	const [wasGamePaused, setWasGamePaused] = useState(false)
	const [, setWindowSize] = useState({ width: 0, height: 0 })
	const [showSpeedBoost, setShowSpeedBoost] = useState(false)
	const [speedBoostText, setSpeedBoostText] = useState('')
	const [totalScore, setTotalScore] = useState(0)
	const [totalFoodEaten, setTotalFoodEaten] = useState(0)
	const [collisionCount, setCollisionCount] = useState(0)

	const isMobileDevice = isMobile()

	// Handle window resize
	useEffect(() => {
		const handleResize = () => {
			setWindowSize({ width: window.innerWidth, height: window.innerHeight })
		}

		window.addEventListener('resize', handleResize)
		handleResize() // Initial call

		return () => window.removeEventListener('resize', handleResize)
	}, [])

	// Handle keyboard input for pause
	useEffect(() => {
		const handleKeyPress = (e: KeyboardEvent) => {
			if (e.key === ' ' || e.key === 'Escape') {
				e.preventDefault()
				if (isGameStarted && !isGameOver) {
					togglePause()
				}
			}
		}

		window.addEventListener('keydown', handleKeyPress)
		return () => window.removeEventListener('keydown', handleKeyPress)
	// eslint-disable-next-line react-hooks/exhaustive-deps
	}, [isGameStarted, isGameOver])

	const togglePause = useCallback(() => {
		if (isGameStarted && !isGameOver) {
			setIsPaused(prev => !prev)
		}
	}, [isGameStarted, isGameOver])

	const startGame = useCallback(() => {
		if (!isGameStarted && images) {
			setIsGameStarted(true)
			setIsGameOver(false)
			setScore(0)
			setTotalScore(0)
			setTotalFoodEaten(0)
			setLives(initialLives)
			setQuitGame(false)
		}
	}, [isGameStarted, images, initialLives])

	const cancelQuit = () => {
		setQuitGame(false)
		setIsPaused(wasGamePaused)
	}

	const handleQuitConfirm = () => {
		setPointsEarned(totalScore)
		setGameOver(true)
		setIsGameStarted(false)
		setIsGameOver(true)
	}

	const handleGameOver = useCallback(() => {
		if (!isGameOver) {
			const newLives = lives - 1
			setLives(newLives)

			if (newLives <= 0) {
				setIsGameOver(true)
				setGameOver(true)
				setPointsEarned(totalScore)
			} else {
				// Continue with remaining lives
				// Force remount the game component
				setCollisionCount(prev => prev + 1)
			}
		}
	}, [isGameOver, lives, totalScore, setGameOver, setPointsEarned])

	const handleScoreUpdate = useCallback(
		(points: number) => {
			const newScore = totalScore + points
			setTotalScore(newScore)
			setScore(newScore)
			setTotalFoodEaten(prev => prev + 1)

			if (maxPoints && newScore >= maxPoints) {
				setIsGameOver(true)
				setGameOver(true)
				setPointsEarned(newScore)
				return
			}

			// Show speed boost notification at certain score thresholds
			const speedThresholds = [50, 100, 200, 300, 500]
			const oldThreshold = speedThresholds.filter(t => totalScore >= t).length
			const newThreshold = speedThresholds.filter(t => newScore >= t).length

			if (newThreshold > oldThreshold) {
				setSpeedBoostText('¡Velocidad Aumentada!')
				setShowSpeedBoost(true)
				setTimeout(() => setShowSpeedBoost(false), 1500)
			}
		},
		// eslint-disable-next-line react-hooks/exhaustive-deps
		[totalScore]
	)

	const handleVirtualControl = useCallback(
		(direction: 'up' | 'down' | 'left' | 'right' | 'action' | 'action2') => {
			if (isGameStarted && !isPaused && !isGameOver) {
				// Create synthetic keyboard event
				const event = new KeyboardEvent('keydown', {
					key: `Arrow${direction.charAt(0).toUpperCase() + direction.slice(1)}`,
					bubbles: true,
				})
				window.dispatchEvent(event)
			}
		},
		[isGameStarted, isPaused, isGameOver]
	)

	// Canvas dimensions (from constants)
	const canvasWidth = DEFAULT_BOARD_SIZE * DEFAULT_CELL_SIZE // 640
	const canvasHeight = canvasWidth + HUD_HEIGHT // 692

	// Calculate canvas scale using actual container width
	const getCanvasScale = () => {
		if (typeof window === 'undefined') return 1

		const padding = isMobileDevice ? 16 : 32
		const headerHeight = 80
		const controlsHeight = isMobileDevice ? 160 : 0
		const extraMargin = 20

		const availableWidth = containerRef.current
			? containerRef.current.clientWidth - padding * 2
			: window.innerWidth - padding * 2
		const availableHeight =
			window.innerHeight - headerHeight - controlsHeight - extraMargin

		const scaleX = availableWidth / canvasWidth
		const scaleY = availableHeight / canvasHeight
		let scale = Math.min(scaleX, scaleY)

		if (isMobileDevice) {
			scale = Math.min(scale, 1.2)
			return Math.max(scale, 0.5)
		} else {
			return Math.min(scale, 1.0) // Never scale above 1 on desktop
		}
	}

	const scale = getCanvasScale()

	return (
		<div
			className="game-container"
			style={{ backgroundColor: brandColor ? brandColor : '#111827' }}
			ref={containerRef}
		>
			{/* Game Header */}
			<GameHeader
				lives={lives}
				score={score}
				onPause={togglePause}
				isPaused={isPaused}
				brandColor={brandColor}
				isMobile={isMobileDevice}
				onQuit={() => {
					setQuitGame(true)
					setWasGamePaused(isPaused)
					setIsPaused(true)
				}}
				showQuitButton={isGameStarted}
				isQuitting={quitGame}
			/>

			{/* Game Canvas */}
			<div className="game-center-area" style={{ position: 'relative' }}>
				<div
					style={{
						width: '100%',
						height: '100%',
					}}
				>
					{/* Loading State */}
					{imagesLoading && (
						<div className="game-loading">
							<div>Cargando...</div>
						</div>
					)}

					{/* Error State */}
					{imagesError && (
						<div className="game-error">
							<div>
								Error al cargar imágenes: {imagesError}
							</div>
						</div>
					)}

					{/* Game */}
					{images && isGameStarted && !isGameOver && (
						<div
							style={{
								width: canvasWidth * scale,
								height: canvasHeight * scale,
								margin: '20px auto',
							}}
						>
							<div
								style={{
									transform: `scale(${scale})`,
									transformOrigin: 'top left',
								}}
							>
								<Suspense fallback={<div className="game-loading-fallback"><div className="game-loading-text game-animate-pulse">Cargando...</div></div>}>
								<SnakeGameCore
									key={collisionCount}
									images={images}
									onScoreUpdate={handleScoreUpdate}
									onLivesUpdate={setLives}
									onGameOver={handleGameOver}
									isPaused={isPaused}
									initialScore={totalScore}
									initialFoodEaten={totalFoodEaten}
								/>
							</Suspense>
							</div>
						</div>
					)}

					{/* Speed Boost Notification */}
					{showSpeedBoost && isGameStarted && !isGameOver && (
						<div className="game-notification">
							<div className="game-notification-content game-animate-pulse">
								<p className="game-notification-text">{speedBoostText}</p>
							</div>
						</div>
					)}

					{/* Game Overlays */}
					{!isGameStarted && images && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={startGame}
							actionText="🎮 JUGAR"
							showPressToStart={false}
							customContent={
								<div className="game-start-content">
									<h1 className="game-start-title game-animate-pulse" style={{ color: '#4ade80' }}>
										{gameTitle}
									</h1>
									{brandLogo && (
										<>
											<span className="game-brand-label">por:</span>
											<img
												src={brandLogo}
												alt="Brand Logo"
												className="game-brand-logo"
											/>
										</>
									)}
									<div className="game-start-instructions">
										<p>🐍 Mueve la serpiente con las flechas</p>
										<p>🍎 Recolecta los items para crecer</p>
										<p>⚡ La velocidad aumenta con los puntos</p>
										<p>💥 No choques contigo mismo</p>
									</div>
									<div className="game-start-footer">
										<p>Usa las flechas del teclado o los controles táctiles</p>
									</div>
								</div>
							}
						/>
					)}

					{isPaused && !isGameOver && (
						<GameOverlay
							type="pause"
							brandColor={brandColor}
							onAction={togglePause}
						/>
					)}

					{isGameOver && (
						<GameOverlay
							type="gameOver"
							score={score}
							brandColor={brandColor}
						/>
					)}

					{/* Quit Confirmation Overlay */}
					{quitGame && (
						<GameOverlay
							type="custom"
							title="¿Salir del Juego?"
							message={`¿Seguro? Registrarás tus puntos actuales (${totalScore}) y perderás las vidas restantes.`}
							brandColor={brandColor}
							customContent={
								<div className="game-quit-buttons">
									<button
										onClick={cancelQuit}
										className="game-quit-btn game-quit-btn-cancel"
									>
										🔄 Cancelar
									</button>
									<button
										onClick={handleQuitConfirm}
										className="game-quit-btn game-quit-btn-confirm"
									>
										❌ Salir Ahora
									</button>
								</div>
							}
						/>
					)}
				</div>
			</div>

			{/* Mobile Controls */}
			{isMobileDevice && isGameStarted && !isGameOver && (
				<GameControls
					onControl={handleVirtualControl}
					brandColor={brandColor}
					layout="arrows"
					showActionButton={false}
				/>
			)}
		</div>
	)
}

export default SnakeGame
