import { useRef, useEffect, useCallback, useState } from 'react'
import { CANVAS_WIDTH, CANVAS_HEIGHT } from './constants'
import { Direction, GameState } from './types'
import { useGameLoop } from './hooks/useGameLoop'
import { useInput } from './hooks/useInput'
import { pacmanAudio } from './utils/audioManager'
import { hapticManager } from '../utils/hapticManager'

interface PacmanGameProps {
	lives: number
	isPaused?: boolean
	onScoreChange?: (score: number) => void
	onLivesUpdate?: (lives: number) => void
	onGameOver?: (score: number) => void
	onLevelComplete?: () => void
	maxPoints?: number
}

export function PacmanGame({
	lives,
	isPaused: externalPaused,
	onScoreChange,
	onLivesUpdate,
	onGameOver,
	onLevelComplete,
	maxPoints,
}: PacmanGameProps) {
	const canvasRef = useRef<HTMLCanvasElement>(null)
	const [isStarted, setIsStarted] = useState(false)
	const [audioInitialized, setAudioInitialized] = useState(false)

	// Initialize audio and haptics on first user interaction
	const initAudio = useCallback(async () => {
		if (!audioInitialized) {
			await pacmanAudio.init()
			hapticManager.init()
			setAudioInitialized(true)
		}
	}, [audioInitialized])

	const { startGame, togglePause, setDirection, getState } = useGameLoop({
		canvasRef,
		initialLives: lives,
		maxPoints,
		onScoreChange,
		onLivesUpdate,
		onGameOver: score => {
			onGameOver?.(score)
		},
		onLevelComplete,
	})

	// Handle direction change
	const handleDirectionChange = useCallback(
		(direction: Direction) => {
			if (isStarted) {
				setDirection(direction)
			}
		},
		[isStarted, setDirection]
	)

	// Handle pause
	const handlePause = useCallback(() => {
		if (isStarted) {
			togglePause()
		}
	}, [isStarted, togglePause])

	// Sync external pause state with game loop
	useEffect(() => {
		if (!isStarted) return

		const shouldBePaused = externalPaused ?? false
		const currentState = getState()
		const isCurrentlyPaused = currentState.gameState === GameState.PAUSED

		if (shouldBePaused && !isCurrentlyPaused) {
			togglePause()
		} else if (!shouldBePaused && isCurrentlyPaused) {
			togglePause()
		}
	}, [externalPaused, isStarted, togglePause, getState])

	// Set up keyboard/touch input
	useInput({
		onDirectionChange: handleDirectionChange,
		onPause: handlePause,
		onInteract: initAudio,
		enabled: isStarted,
	})

	// Start game when component mounts
	useEffect(() => {
		if (canvasRef.current && !isStarted) {
			setIsStarted(true)
			startGame()
		}
	}, [isStarted, startGame])

	// Cleanup audio on unmount
	useEffect(() => {
		return () => {
			pacmanAudio.dispose()
		}
	}, [])

	return (
		<div className="game-pacman-wrapper">
			{/* Game Canvas */}
			<canvas
				ref={canvasRef}
				width={CANVAS_WIDTH}
				height={CANVAS_HEIGHT}
				className="game-pacman-canvas"
				style={{
					imageRendering: 'pixelated',
					maxWidth: '100%',
					height: 'auto',
				}}
				onClick={initAudio}
				onTouchStart={initAudio}
			/>

			{/* Desktop instructions */}
			<div className="game-pacman-instructions">
				<p>Use arrow keys or WASD to move</p>
				<p>Press SPACE or P to pause</p>
			</div>
		</div>
	)
}
