import React, { useRef, useEffect, useState, useCallback } from 'react'
import { PacmanGame } from './game'
import { GameHeader } from '../ui/GameHeader'
import { GameOverlay } from '../ui/GameOverlay'
import { GameControls } from '../ui/GameControls'
import { isMobile } from '../../../../utils/functions'
import { Direction } from './types'

interface PacmanGameWrapperProps {
	lives: number
	setGameOver: (isOver: boolean) => void
	setPointsEarned: (points: number) => void
	brandColor?: string
	gameTitle?: string
	maxPoints?: number
	brandLogo?: string
	skin?: string
}

const PacmanGameWrapper: React.FC<PacmanGameWrapperProps> = ({
	lives: initialLives,
	setGameOver,
	setPointsEarned,
	brandColor = '#2121ff',
	gameTitle = 'PAC-MAN',
	maxPoints,
	brandLogo,
	skin: _skin,
}) => {
	const containerRef = useRef<HTMLDivElement>(null)

	const [score, setScore] = useState(0)
	const [lives, setLives] = useState(initialLives)
	const [isPaused, setIsPaused] = useState(false)
	const [isGameStarted, setIsGameStarted] = useState(false)
	const [isGameOver, setIsGameOver] = useState(false)
	const [quitGame, setQuitGame] = useState(false)
	const [wasGamePaused, setWasGamePaused] = useState(false)
	const [, setWindowSize] = useState({ width: 0, height: 0 })

	const isMobileDevice = isMobile()

	// Handle window resize
	useEffect(() => {
		const handleResize = () => {
			setWindowSize({ width: window.innerWidth, height: window.innerHeight })
		}

		window.addEventListener('resize', handleResize)
		handleResize()

		return () => window.removeEventListener('resize', handleResize)
	}, [])

	const togglePause = useCallback(() => {
		if (isGameStarted && !isGameOver) {
			setIsPaused(prev => !prev)
		}
	}, [isGameStarted, isGameOver])

	// Handle keyboard input for pause
	useEffect(() => {
		const handleKeyPress = (e: KeyboardEvent) => {
			if (
				e.key === ' ' ||
				e.key === 'Escape' ||
				e.key === 'p' ||
				e.key === 'P'
			) {
				e.preventDefault()
				if (isGameStarted && !isGameOver) {
					togglePause()
				}
			}
		}

		window.addEventListener('keydown', handleKeyPress)
		return () => window.removeEventListener('keydown', handleKeyPress)
	}, [isGameStarted, isGameOver, togglePause])

	const startGame = useCallback(() => {
		if (!isGameStarted) {
			setIsGameStarted(true)
			setIsGameOver(false)
			setScore(0)
			setLives(initialLives)
			setQuitGame(false)
		}
	}, [isGameStarted, initialLives])

	const cancelQuit = () => {
		setQuitGame(false)
		setIsPaused(wasGamePaused)
	}

	const handleQuitConfirm = () => {
		setPointsEarned(score)
		setGameOver(true)
		setIsGameStarted(false)
		setIsGameOver(true)
	}

	const handleGameOver = useCallback(
		(finalScore: number) => {
			setIsGameOver(true)
			setGameOver(true)
			setPointsEarned(finalScore)
		},
		[setGameOver, setPointsEarned]
	)

	const handleScoreChange = useCallback((newScore: number) => {
		setScore(newScore)
	}, [])

	const handleVirtualControl = useCallback(
		(direction: 'up' | 'down' | 'left' | 'right' | 'action' | 'action2') => {
			if (isGameStarted && !isPaused && !isGameOver) {
				// Map to Direction enum
				const dirMap: Record<string, Direction | undefined> = {
					up: Direction.UP,
					down: Direction.DOWN,
					left: Direction.LEFT,
					right: Direction.RIGHT,
				}
				const dir = dirMap[direction]
				if (dir !== undefined) {
					// Dispatch keyboard event for the game to pick up
					const keyMap: Record<Direction, string> = {
						[Direction.UP]: 'ArrowUp',
						[Direction.DOWN]: 'ArrowDown',
						[Direction.LEFT]: 'ArrowLeft',
						[Direction.RIGHT]: 'ArrowRight',
					}
					const event = new KeyboardEvent('keydown', {
						key: keyMap[dir],
						bubbles: true,
					})
					window.dispatchEvent(event)
				}
			}
		},
		[isGameStarted, isPaused, isGameOver]
	)

	return (
		<div
			className="game-container"
			style={{ backgroundColor: '#000' }}
			ref={containerRef}
		>
			{/* Game Header */}
			<GameHeader
				lives={lives}
				score={score}
				onPause={togglePause}
				isPaused={isPaused}
				brandColor={brandColor}
				isMobile={isMobileDevice}
				onQuit={() => {
					setQuitGame(true)
					setWasGamePaused(isPaused)
					setIsPaused(true)
				}}
				showQuitButton={isGameStarted}
				isQuitting={quitGame}
			/>

			{/* Game Canvas */}
			<div className="game-center-area">
				<div
					className="game-relative-area"
					style={{ minHeight: '400px', height: '100%' }}
				>
					{/* Game */}
					{isGameStarted && !isGameOver && (
						<PacmanGame
							lives={lives}
							isPaused={isPaused}
							onScoreChange={handleScoreChange}
							onLivesUpdate={setLives}
							onGameOver={handleGameOver}
							maxPoints={maxPoints}
						/>
					)}

					{/* Game Overlays */}
					{!isGameStarted && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={startGame}
							actionText="🎮 JUGAR"
							showPressToStart={false}
							customContent={
								<div className="game-start-content">
									<h1
										className="game-start-title game-animate-pulse"
										style={{ color: '#facc15' }}
									>
										{gameTitle}
									</h1>
									{brandLogo && (
										<>
											<span className="game-brand-label">por:</span>
											<img
												src={brandLogo}
												alt="Brand Logo"
												className="game-brand-logo"
											/>
										</>
									)}
									<div className="game-start-instructions">
										<p>👻 Come todas las bolitas</p>
										<p>💊 Las bolitas grandes te dan poder</p>
										<p>⚡ Come a los fantasmas azules</p>
										<p>💀 Evita a los fantasmas normales</p>
									</div>
									<div className="game-start-footer">
										<p>Usa las flechas del teclado o los controles táctiles</p>
									</div>
								</div>
							}
						/>
					)}

					{isPaused && !isGameOver && !quitGame && (
						<GameOverlay
							type="pause"
							brandColor={brandColor}
							onAction={togglePause}
						/>
					)}

					{isGameOver && (
						<GameOverlay
							type="gameOver"
							score={score}
							brandColor={brandColor}
						/>
					)}

					{/* Quit Confirmation Overlay */}
					{quitGame && (
						<GameOverlay
							type="custom"
							title="¿Salir del Juego?"
							message={`¿Seguro? Registrarás tus puntos actuales (${score}) y perderás las vidas restantes.`}
							brandColor={brandColor}
							customContent={
								<div className="game-quit-buttons">
									<button
										onClick={cancelQuit}
										className="game-quit-btn game-quit-btn-cancel"
									>
										🔄 Cancelar
									</button>
									<button
										onClick={handleQuitConfirm}
										className="game-quit-btn game-quit-btn-confirm"
									>
										❌ Salir Ahora
									</button>
								</div>
							}
						/>
					)}
				</div>
			</div>

			{/* Mobile Controls */}
			{isMobileDevice && isGameStarted && !isGameOver && (
				<GameControls
					onControl={handleVirtualControl}
					brandColor={brandColor}
					layout="arrows"
					showActionButton={false}
				/>
			)}
		</div>
	)
}

export default PacmanGameWrapper
